import{_ as i,o as s,c as e,ae as d}from"./chunks/framework.D0EcU_Ug.js";const k=JSON.parse('{"title":"Nvidia 独显优先：Wayland 下的基础设置","description":"","frontmatter":{},"headers":[],"relativePath":"notes/graphics/nvidia-wayland.md","filePath":"notes/graphics/nvidia-wayland.md"}'),n={name:"notes/graphics/nvidia-wayland.md"};function t(l,a,p,o,h,r){return s(),e("div",null,[...a[0]||(a[0]=[d(`<h1 id="nvidia-独显优先-wayland-下的基础设置" tabindex="-1">Nvidia 独显优先：Wayland 下的基础设置 <a class="header-anchor" href="#nvidia-独显优先-wayland-下的基础设置" aria-label="Permalink to &quot;Nvidia 独显优先：Wayland 下的基础设置&quot;">​</a></h1><p>先装好驱动包：</p><ul><li><code>nvidia</code></li><li><code>nvidia-settings</code></li><li><code>nvidia-utils</code></li></ul><p>如果你用的是 50 系显卡，这里的内核模块一般应该换成 <code>nvidia-open</code>。</p><h2 id="_1-打开-nvidia-drm-modeset-1" tabindex="-1">1. 打开 <code>nvidia_drm.modeset=1</code> <a class="header-anchor" href="#_1-打开-nvidia-drm-modeset-1" aria-label="Permalink to &quot;1. 打开 \`nvidia_drm.modeset=1\`&quot;">​</a></h2><p>改 <code>/etc/default/grub</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GRUB_CMDLINE_LINUX_DEFAULT=&quot;nvidia_drm.modeset=1&quot;</span></span></code></pre></div><p>不是整行替换，只是把 <code>nvidia_drm.modeset=1</code> 加进原有参数里。</p><h2 id="_2-让桌面环境优先用独显" tabindex="-1">2. 让桌面环境优先用独显 <a class="header-anchor" href="#_2-让桌面环境优先用独显" aria-label="Permalink to &quot;2. 让桌面环境优先用独显&quot;">​</a></h2><p>先确认显卡对应的设备：</p><ol><li><code>lspci | grep -E &quot;VGA&quot;</code> 找到独显的 PCI 地址，比如 <code>01:00.0</code></li><li><code>ls -l /dev/dri/by-path/</code> 找到它对应的 <code>cardX</code> 和 <code>renderDXXX</code></li></ol><h3 id="kde" tabindex="-1">KDE <a class="header-anchor" href="#kde" aria-label="Permalink to &quot;KDE&quot;">​</a></h3><p>创建 <code>~/.config/plasma-workspace/env/kwin-drm.sh</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/bash</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KWIN_DRM_DEVICES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/dev/dri/card0:/dev/dri/card1&quot;</span></span></code></pre></div><h3 id="hyprland" tabindex="-1">Hyprland <a class="header-anchor" href="#hyprland" aria-label="Permalink to &quot;Hyprland&quot;">​</a></h3><p>在 Hyprland 或 uwsm 配置里加：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AQ_DRM_DEVICES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/dev/dri/card0:/dev/dri/card1&quot;</span></span></code></pre></div><h3 id="niri" tabindex="-1">Niri <a class="header-anchor" href="#niri" aria-label="Permalink to &quot;Niri&quot;">​</a></h3><p>在 <code>~/.config/niri/config.kdl</code> 之类的配置文件里加：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>debug {</span></span>
<span class="line"><span>    render-drm-device &quot;/dev/dri/renderD128&quot;</span></span>
<span class="line"><span>    ignore-drm-device &quot;/dev/dri/renderD129&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>ignore-drm-device</code> 不是必填。它会直接禁掉对应显卡，用错了可能导致内屏或者外接屏点不亮。</p><h2 id="_3-验证模块是否正常" tabindex="-1">3. 验证模块是否正常 <a class="header-anchor" href="#_3-验证模块是否正常" aria-label="Permalink to &quot;3. 验证模块是否正常&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvidia</span></span></code></pre></div><p>正常情况下能看到 <code>nvidia_drm</code> 之类的模块。</p><h2 id="_4-如果功耗上不去" tabindex="-1">4. 如果功耗上不去 <a class="header-anchor" href="#_4-如果功耗上不去" aria-label="Permalink to &quot;4. 如果功耗上不去&quot;">​</a></h2><p>看一下 <code>nvidia-smi</code>。如果显卡的最大功率明显低于预期，可以开：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvidia-powerd.service</span></span></code></pre></div><p>然后再看一次 <code>nvidia-smi</code>。</p>`,28)])])}const u=i(n,[["render",t]]);export{k as __pageData,u as default};
